// HasUnits applies the HasEdge predicate on the "units" edge.
func HasUnits() predicate.UnitCategory {
	return predicate.UnitCategory(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, UnitsTable, UnitsColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasUnitsWith applies the HasEdge predicate on the "units" edge with a given conditions (other predicates).
func HasUnitsWith(preds ...predicate.Unit) predicate.UnitCategory {
	return predicate.UnitCategory(func(s *sql.Selector) {
		step := newUnitsStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.UnitCategory) predicate.UnitCategory {
	return predicate.UnitCategory(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.UnitCategory) predicate.UnitCategory {
	return predicate.UnitCategory(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.UnitCategory) predicate.UnitCategory {
	return predicate.UnitCategory(sql.NotPredicates(p))
}
